#include "qp/features/rolling_variance.hpp"
#include <cmath>
namespace qp::features { RollingVariance::RollingVariance(std::size_t w,bool sample,std::string n): name_(n.empty()?"rolling_variance_"+std::to_string(w):std::move(n)), capacity_(w), sample_(sample){} std::string_view RollingVariance::name() const noexcept{return name_;} Result<std::optional<FeatureValue>> RollingVariance::update(const data::MarketData& d){ auto valid=data::validate(d); if(!valid) return Err<std::optional<FeatureValue>>(valid.error()); const auto& sym=data::symbol(d); auto [it,_]=windows_.try_emplace(sym, capacity_); auto& window=it->second; window.push(data::reference_price(d)); if(!window.full()) return Ok(std::optional<FeatureValue>{}); double m=window.mean(); double ss=0.0; for(double v: window.values()) ss+=(v-m)*(v-m); double denom=sample_ && window.size()>1 ? static_cast<double>(window.size()-1) : static_cast<double>(window.size()); return Ok(std::optional<FeatureValue>{FeatureValue{data::timestamp(d), sym, name_, ss/denom}}); } void RollingVariance::reset(){ windows_.clear(); } }
